SET CLIENT_ENCODING TO UTF8;
SET STANDARD_CONFORMING_STRINGS TO ON;
BEGIN;
CREATE TABLE "construccion_urbana" (gid serial,
"objectid" float8,
"identifica" varchar(20),
"codigo_con" varchar(30),
"tipo_const" int4,
"tipo_domin" int4,
"numero_pis" int4,
"numero_sot" int4,
"numero_mez" int4,
"numero_sem" int4,
"anio_const" int4,
"avaluo_con" numeric,
"avaluo_com" numeric,
"altura" numeric,
"observacio" varchar(254),
"dimension" int4,
"etiqueta" varchar(254),
"relacion_s" int4,
"espacio_de" varchar(254),
"local_id" varchar(254),
"created_us" varchar(254),
"created_da" date,
"last_edite" varchar(254),
"last_edi_1" date,
"globalid" varchar(38),
"shape_leng" numeric,
"shape_area" numeric);
ALTER TABLE "construccion_urbana" ADD PRIMARY KEY (gid);
SELECT AddGeometryColumn('','construccion_urbana','geom','4326','MULTIPOLYGON',2);
CREATE INDEX ON "construccion_urbana" USING GIST ("geom");
COMMIT;
ANALYZE "construccion_urbana";
